import crypto from 'node:crypto';

function checkAppleCredentials(decryptedKey: { username: string; password: string }, username: string, password: string): boolean {
  const usernameBuffer1 = Buffer.from(decryptedKey.username);
  const usernameBuffer2 = Buffer.from(username);

  const passwordBuffer1 = Buffer.from(decryptedKey.password);
  const passwordBuffer2 = Buffer.from(password);

  if (usernameBuffer1.length !== usernameBuffer2.length || passwordBuffer1.length !== passwordBuffer2.length) {
    return false;
  }

  const usernameMatch = crypto.timingSafeEqual(usernameBuffer1, usernameBuffer2);
  const passwordMatch = crypto.timingSafeEqual(passwordBuffer1, passwordBuffer2);

  return usernameMatch && passwordMatch;
}
```

