import crypto from 'node:crypto';

function checkAppleCredentials(decryptedKey: { username: string; password: string }, username: string, password: string): boolean {
  const usernameA = Buffer.from(decryptedKey.username);
  const usernameB = Buffer.from(username);
  if (usernameA.length === usernameB.length && crypto.timingSafeEqual(usernameA, usernameB)) {
    const passwordA = Buffer.from(decryptedKey.password);
    const passwordB = Buffer.from(password);
    if (passwordA.length === passwordB.length && crypto.timingSafeEqual(passwordA, passwordB)) {
      return true;
    }
  }
  return false;
}
