function checkAppleCredentials(decryptedKey: { username: string; password: string }, username: string, password: string): boolean {
  if (decryptedKey.username === username) {
    const a = Buffer.from(decryptedKey.password);
    const b = Buffer.from(password);
    if (a.length === b.length && crypto.timingSafeEqual(a, b)) {
      return true;
    }
  }
  return false;
}
